import type {
  SDUIActionDescriptor,
  SDUIActionContext,
  SDUIActionDeps,
  SDUIActionHandler,
  SDUIActionRegistry,
  SDUIActionResult,
  SDUIContext,
} from '../models';
import { interpolateDeep } from '../utils/interpolation';

const ANALYTICS_ACTIONS: ReadonlySet<string> = new Set([
  'trackScreenView',
  'trackSelect',
  'trackModalView',
]);

export function createActionRegistry(
  initial?: SDUIActionRegistry,
): SDUIActionRegistry {
  return { ...initial };
}

export function registerAction(
  registry: SDUIActionRegistry,
  type: string,
  handler: SDUIActionHandler,
): SDUIActionRegistry {
  return { ...registry, [type]: handler };
}

export function getActionHandler(
  registry: SDUIActionRegistry,
  type: string,
): SDUIActionHandler | undefined {
  return registry[type];
}

function buildMergedContext(actionContext: SDUIActionContext): SDUIContext {
  return {
    ...actionContext.screen,
    form: actionContext.form as unknown as SDUIContext,
  };
}

export async function executeAction(
  registry: SDUIActionRegistry,
  descriptor: SDUIActionDescriptor,
  actionContext: SDUIActionContext,
  deps: SDUIActionDeps,
): Promise<SDUIActionResult> {
  const handler = registry[descriptor.type];
  if (!handler) {
    if (__DEV__) {
      console.warn(`[SDUI] Unknown action type: "${descriptor.type}"`);
    }
    return { success: false, error: `Unknown action type: "${descriptor.type}"` };
  }

  const mergedContext = buildMergedContext(actionContext);
  const interpolatedPayload = descriptor.payload
    ? interpolateDeep(descriptor.payload, mergedContext)
    : undefined;

  try {
    return await handler(interpolatedPayload, actionContext, deps);
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    if (__DEV__) {
      console.error(`[SDUI] Action "${descriptor.type}" threw:`, message);
    }
    return { success: false, error: message };
  }
}

export async function executeActions(
  registry: SDUIActionRegistry,
  descriptors: SDUIActionDescriptor[],
  actionContext: SDUIActionContext,
  deps: SDUIActionDeps,
): Promise<SDUIActionResult[]> {
  const results: SDUIActionResult[] = new Array(descriptors.length);

  const analyticsIndices: number[] = [];
  const primaryIndices: number[] = [];

  for (let i = 0; i < descriptors.length; i++) {
    if (ANALYTICS_ACTIONS.has(descriptors[i].type)) {
      analyticsIndices.push(i);
    } else {
      primaryIndices.push(i);
    }
  }

  for (const i of primaryIndices) {
    if (deps.signal?.aborted) {
      results[i] = { success: false, error: 'Aborted' };
      continue;
    }
    results[i] = await executeAction(registry, descriptors[i], actionContext, deps);
  }

  for (const i of analyticsIndices) {
    results[i] = await executeAction(registry, descriptors[i], actionContext, deps);
  }

  return results;
}

const defaultActionRegistry: SDUIActionRegistry = {};

export function getDefaultActionRegistry(): SDUIActionRegistry {
  return defaultActionRegistry;
}

export function registerToDefaultActions(
  type: string,
  handler: SDUIActionHandler,
): void {
  defaultActionRegistry[type] = handler;
}

declare const __DEV__: boolean;

export {
  createActionRegistry,
  registerAction,
  getActionHandler,
  executeAction,
  executeActions,
  getDefaultActionRegistry,
  registerToDefaultActions,
} from './registry';

