import type {
  SDUIActionContext,
  SDUIActionDeps,
} from '../models';
import {
  navigateHandler,
  goBackHandler,
  replaceHandler,
  deepLinkHandler,
} from './navigation';

const mockSetForm = jest.fn();

const mockActionContext: SDUIActionContext = {
  screen: {},
  form: {},
  setForm: mockSetForm,
};

function createNavDeps(overrides?: Partial<SDUIActionDeps>): SDUIActionDeps {
  return {
    navigation: {
      navigate: jest.fn(),
      goBack: jest.fn(),
      replace: jest.fn(),
    },
    linking: {
      openURL: jest.fn(),
    },
    ...overrides,
  };
}

describe('navigateHandler', () => {
  it('calls navigation.navigate with screen and params', () => {
    const deps = createNavDeps();
    const result = navigateHandler(
      { screen: 'VoucherSummary', params: { points: 5000 } },
      mockActionContext,
      deps,
    );

    expect(result.success).toBe(true);
    expect(deps.navigation!.navigate).toHaveBeenCalledWith('VoucherSummary', { points: 5000 });
  });

  it('calls navigation.navigate with screen only (no params)', () => {
    const deps = createNavDeps();
    const result = navigateHandler(
      { screen: 'Home' },
      mockActionContext,
      deps,
    );

    expect(result.success).toBe(true);
    expect(deps.navigation!.navigate).toHaveBeenCalledWith('Home', undefined);
  });

  it('fails when navigation dependency is missing', () => {
    const result = navigateHandler(
      { screen: 'Home' },
      mockActionContext,
      {},
    );

    expect(result.success).toBe(false);
    expect(result.error).toContain('Navigation dependency not provided');
  });

  it('fails when payload has no screen', () => {
    const deps = createNavDeps();
    const result = navigateHandler({ params: {} }, mockActionContext, deps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('requires a "screen"');
  });

  it('fails when screen is not a string', () => {
    const deps = createNavDeps();
    const result = navigateHandler({ screen: 123 }, mockActionContext, deps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('requires a "screen"');
  });

  it('fails when payload is undefined', () => {
    const deps = createNavDeps();
    const result = navigateHandler(undefined, mockActionContext, deps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('requires a "screen"');
  });
});

describe('goBackHandler', () => {
  it('calls navigation.goBack', () => {
    const deps = createNavDeps();
    const result = goBackHandler(undefined, mockActionContext, deps);

    expect(result.success).toBe(true);
    expect(deps.navigation!.goBack).toHaveBeenCalled();
  });

  it('ignores payload (goBack needs no arguments)', () => {
    const deps = createNavDeps();
    const result = goBackHandler({ anything: 'ignored' }, mockActionContext, deps);

    expect(result.success).toBe(true);
    expect(deps.navigation!.goBack).toHaveBeenCalled();
  });

  it('fails when navigation dependency is missing', () => {
    const result = goBackHandler(undefined, mockActionContext, {});

    expect(result.success).toBe(false);
    expect(result.error).toContain('Navigation dependency not provided');
  });
});

describe('replaceHandler', () => {
  it('calls navigation.replace with screen and params', () => {
    const deps = createNavDeps();
    const result = replaceHandler(
      { screen: 'Success', params: { orderId: 'abc' } },
      mockActionContext,
      deps,
    );

    expect(result.success).toBe(true);
    expect(deps.navigation!.replace).toHaveBeenCalledWith('Success', { orderId: 'abc' });
  });

  it('calls navigation.replace with screen only', () => {
    const deps = createNavDeps();
    const result = replaceHandler({ screen: 'Home' }, mockActionContext, deps);

    expect(result.success).toBe(true);
    expect(deps.navigation!.replace).toHaveBeenCalledWith('Home', undefined);
  });

  it('fails when navigation dependency is missing', () => {
    const result = replaceHandler({ screen: 'Home' }, mockActionContext, {});

    expect(result.success).toBe(false);
    expect(result.error).toContain('Navigation dependency not provided');
  });

  it('fails when payload has no screen', () => {
    const deps = createNavDeps();
    const result = replaceHandler({}, mockActionContext, deps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('requires a "screen"');
  });
});

describe('deepLinkHandler', () => {
  it('calls linking.openURL with the url', () => {
    const deps = createNavDeps();
    const result = deepLinkHandler(
      { url: 'app://rewards/voucher/123' },
      mockActionContext,
      deps,
    );

    expect(result.success).toBe(true);
    expect(deps.linking!.openURL).toHaveBeenCalledWith('app://rewards/voucher/123');
  });

  it('handles tel: URIs', () => {
    const deps = createNavDeps();
    const result = deepLinkHandler(
      { url: 'tel:40021552' },
      mockActionContext,
      deps,
    );

    expect(result.success).toBe(true);
    expect(deps.linking!.openURL).toHaveBeenCalledWith('tel:40021552');
  });

  it('handles https URLs', () => {
    const deps = createNavDeps();
    const result = deepLinkHandler(
      { url: 'https://semparar.com.br/rules' },
      mockActionContext,
      deps,
    );

    expect(result.success).toBe(true);
    expect(deps.linking!.openURL).toHaveBeenCalledWith('https://semparar.com.br/rules');
  });

  it('fails when linking dependency is missing', () => {
    const result = deepLinkHandler(
      { url: 'app://test' },
      mockActionContext,
      {},
    );

    expect(result.success).toBe(false);
    expect(result.error).toContain('Linking dependency not provided');
  });

  it('fails when payload has no url', () => {
    const deps = createNavDeps();
    const result = deepLinkHandler({}, mockActionContext, deps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('requires a "url"');
  });

  it('fails when url is not a string', () => {
    const deps = createNavDeps();
    const result = deepLinkHandler({ url: 42 }, mockActionContext, deps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('requires a "url"');
  });

  it('fails when payload is undefined', () => {
    const deps = createNavDeps();
    const result = deepLinkHandler(undefined, mockActionContext, deps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('requires a "url"');
  });
});

describe('integration with ActionRegistry', () => {
  it('handlers work with executeAction via registry', async () => {
    const { createActionRegistry, executeAction } = require('./registry');
    const deps = createNavDeps();

    let registry = createActionRegistry();
    registry = { ...registry, navigate: navigateHandler, goBack: goBackHandler };

    const navResult = await executeAction(
      registry,
      { type: 'navigate', payload: { screen: 'Detail', params: { id: '1' } } },
      mockActionContext,
      deps,
    );
    expect(navResult.success).toBe(true);
    expect(deps.navigation!.navigate).toHaveBeenCalledWith('Detail', { id: '1' });

    const backResult = await executeAction(
      registry,
      { type: 'goBack' },
      mockActionContext,
      deps,
    );
    expect(backResult.success).toBe(true);
    expect(deps.navigation!.goBack).toHaveBeenCalled();
  });
});

