import React, { useState } from 'react';
import { View, ScrollView } from 'react-native';
import { Text, Box, Button, SeparatorHorizontal } from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIScreen } from '../services/sdui/models';
import ScreenRenderer from '../services/sdui/renderer/ScreenRenderer';
import { registerAllAdapters } from '../services/sdui/adapters';

registerAllAdapters();

function buildScreen(pointsValue: number, showRules: boolean): SDUIScreen {
  return {
    id: 'conditionals_demo',
    context: {
      form: { points: pointsValue },
      balance: { available: 1000 },
      flags: { showRules },
    },
    body: [
      {
        type: 'heading',
        props: { text: 'Conditional Visibility Demo' },
      },
      {
        type: 'text',
        props: {
          text: `Points entered: ${pointsValue} | Balance: 1,000 | Show rules: ${showRules}`,
        },
      },
      {
        type: 'separator',
        props: {},
      },
      {
        type: 'balance_display',
        props: {
          label: 'Pontos disponíveis:',
          pointsFormatted: '1.000',
          priceFormatted: 'R$ 10,00',
        },
      },
      {
        type: 'text',
        props: { text: 'This alert only shows when points > 0:' },
      },
      {
        type: 'alert',
        props: {
          label: `Você selecionou ${pointsValue} pontos`,
          type: 'highlight',
        },
        visible: {
          rule: { '>': [{ var: 'form.points' }, 0] },
        },
      },
      {
        type: 'text',
        props: { text: 'This warning only shows when points > balance:' },
      },
      {
        type: 'alert',
        props: {
          label: 'Pontos insuficientes! Você não tem saldo suficiente.',
          type: 'attention',
        },
        visible: {
          rule: {
            '>': [
              { var: 'form.points' },
              { var: 'balance.available' },
            ],
          },
        },
      },
      {
        type: 'separator',
        props: {},
      },
      {
        type: 'section_heading',
        props: { text: 'Regras de uso' },
        visible: {
          rule: { '==': [{ var: 'flags.showRules' }, true] },
        },
      },
      {
        type: 'icon_text_row',
        props: { icon: 'icon-check-circle', text: 'Válido por 30 dias' },
        visible: {
          rule: { '==': [{ var: 'flags.showRules' }, true] },
        },
      },
      {
        type: 'icon_text_row',
        props: { icon: 'icon-check-circle', text: 'Uso único por transação' },
        visible: {
          rule: { '==': [{ var: 'flags.showRules' }, true] },
        },
      },
      {
        type: 'separator',
        props: {},
      },
      {
        type: 'button',
        props: {
          text: 'Criar voucher',
          enabled: {
            rule: {
              and: [
                { '>': [{ var: 'form.points' }, 0] },
                {
                  '<=': [
                    { var: 'form.points' },
                    { var: 'balance.available' },
                  ],
                },
              ],
            },
          },
        },
      },
      {
        type: 'text',
        props: {
          text: 'Button is enabled only when: points > 0 AND points <= balance',
          variant: 'bodySM',
          color: 'INTENSE_COLOR_03',
        },
      },
    ],
  };
}

function ConditionalsDemo() {
  const [points, setPoints] = useState(0);
  const [showRules, setShowRules] = useState(true);

  const screen = buildScreen(points, showRules);

  return (
    <ScrollView style={{ flex: 1 }}>
      <Box p="xxxs">
        <Text type="headingMDL" mb="nano">
          SDUI Conditionals
        </Text>
        <Text type="bodySM" color="INTENSE_COLOR_03" mb="xs">
          Demonstrates component visibility and button enabled state via JSON
          Logic rules evaluated against context.
        </Text>

        <Box direction mb="xs" style={{ gap: 8 }}>
          {[0, 500, 1000, 1500].map(v => (
            <View
              key={v}
              style={{
                backgroundColor: points === v ? '#0066FF' : '#E0E0E0',
                borderRadius: 8,
                paddingHorizontal: 12,
                paddingVertical: 6,
              }}
            >
              <Text
                type="bodySM"
                color={points === v ? 'BRIGHT_COLOR_01' : 'DEEP_COLOR_01'}
                onPress={() => setPoints(v)}
              >
                {v} pts
              </Text>
            </View>
          ))}
        </Box>

        <Box direction mb="xs" style={{ gap: 8 }}>
          <View
            style={{
              backgroundColor: showRules ? '#0066FF' : '#E0E0E0',
              borderRadius: 8,
              paddingHorizontal: 12,
              paddingVertical: 6,
            }}
          >
            <Text
              type="bodySM"
              color={showRules ? 'BRIGHT_COLOR_01' : 'DEEP_COLOR_01'}
              onPress={() => setShowRules(!showRules)}
            >
              {showRules ? 'Hide rules' : 'Show rules'}
            </Text>
          </View>
        </Box>

        <SeparatorHorizontal mv="xs" />

        <ScreenRenderer screen={screen} />
      </Box>
    </ScrollView>
  );
}

const meta: Meta = {
  title: 'SDUI/Conditionals',
  component: ConditionalsDemo,
};

export default meta;

type Story = StoryObj<typeof meta>;

export const Demo: Story = {};

