import { chromium } from 'playwright';

const STORYBOOK_URL = 'http://localhost:6008';

async function main() {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1600, height: 1000 } });

  // Navigate to SDUI VoucherDemo Form story
  await page.goto(`${STORYBOOK_URL}/?path=/story/sdui-voucherdemo--form`, { waitUntil: 'networkidle' });
  await page.waitForTimeout(4000);

  // Light mode - full resolution
  await page.screenshot({ path: '.storybook/screenshots/editor-light-hires.png', fullPage: false });
  console.log('Light mode hi-res saved');

  // Check what classes/attributes Storybook uses for dark mode
  const bodyClasses = await page.evaluate(() => document.body.className);
  const htmlAttrs = await page.evaluate(() => {
    const attrs = {};
    for (const attr of document.documentElement.attributes) {
      attrs[attr.name] = attr.value;
    }
    return attrs;
  });
  const bodyBg = await page.evaluate(() => getComputedStyle(document.body).backgroundColor);
  console.log('Body classes:', bodyClasses);
  console.log('HTML attributes:', JSON.stringify(htmlAttrs));
  console.log('Body background:', bodyBg);

