import React, { useState, useCallback, useRef } from 'react';
import { View, ScrollView } from 'react-native';
import { Text, Box, Button, SeparatorHorizontal } from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIActionDescriptor, SDUIActionContext, SDUIActionDeps } from '../services/sdui/models';
import {
  createActionRegistry,
  executeAction,
  navigateHandler,
  goBackHandler,
  replaceHandler,
  deepLinkHandler,
} from '../services/sdui/actions';

interface ActionLogEntry {
  id: number;
  type: string;
  payload?: Record<string, unknown>;
  result: { success: boolean; error?: string };
  timestamp: string;
}

function NavigationActionsDemo() {
  const [log, setLog] = useState<ActionLogEntry[]>([]);
  const idRef = useRef(0);

  const registry = useRef(
    (() => {
      let r = createActionRegistry();
      r = { ...r, navigate: navigateHandler, goBack: goBackHandler, replace: replaceHandler, deepLink: deepLinkHandler };
      return r;
    })(),
  ).current;

  const actionContext: SDUIActionContext = {
    screen: { product: { name: 'Abastecimento' } as unknown as string },
    form: { points: 5000 },
    setForm: () => {},
  };

  const deps: SDUIActionDeps = {
    navigation: {
      navigate: (screen, params) => console.log('[NAV] navigate →', screen, params),
      goBack: () => console.log('[NAV] goBack'),
      replace: (screen, params) => console.log('[NAV] replace →', screen, params),
    },
    linking: {
      openURL: (url) => console.log('[LINK] openURL →', url),
    },
  };

  const fire = useCallback(async (descriptor: SDUIActionDescriptor) => {
    const result = await executeAction(registry, descriptor, actionContext, deps);
    idRef.current += 1;
    const entry: ActionLogEntry = {
      id: idRef.current,
      type: descriptor.type,
      payload: descriptor.payload,
      result: { success: result.success, error: result.error },
      timestamp: new Date().toLocaleTimeString(),
    };
    setLog(prev => [entry, ...prev].slice(0, 20));
  }, []);

  return (
    <ScrollView style={{ flex: 1 }}>
      <Box p="xxxs">
        <Text type="headingMDL" mb="nano">
          SDUI Navigation Actions
        </Text>
        <Text type="bodySM" color="INTENSE_COLOR_03" mb="xs">
          Demonstrates all 4 navigation action handlers. Actions call console.log
          stubs (check DevTools console). Action log below shows results.
        </Text>

        <SeparatorHorizontal mv="xs" />

        <Text type="subtitleXXL" mb="nano">navigate</Text>
        <Box mb="xs" style={{ gap: 8 }}>
          <Button
            text="Navigate → VoucherSummary"
            onPress={() => fire({
              type: 'navigate',
              payload: { screen: 'VoucherSummary', params: { points: '{{form.points}}' } },
            })}
          />
          <Button
            text="Navigate → Home (no params)"
            onPress={() => fire({
              type: 'navigate',
              payload: { screen: 'RewardProgram' },
            })}
          />
        </Box>

        <Text type="subtitleXXL" mb="nano">goBack</Text>
        <Box mb="xs">
          <Button
            text="Go Back"
            onPress={() => fire({ type: 'goBack' })}
          />
        </Box>

        <Text type="subtitleXXL" mb="nano">replace</Text>
        <Box mb="xs">
          <Button
            text="Replace → SuccessScreen"
            onPress={() => fire({
              type: 'replace',
              payload: { screen: 'SuccessScreen', params: { orderId: 'ORD-001' } },
            })}
          />
        </Box>

        <Text type="subtitleXXL" mb="nano">deepLink</Text>
        <Box mb="xs" style={{ gap: 8 }}>
          <Button
            text="Deep Link → app://rewards/voucher/123"
            onPress={() => fire({
              type: 'deepLink',
              payload: { url: 'app://rewards/voucher/123' },
            })}
          />
          <Button
            text="Deep Link → tel:40021552"
            onPress={() => fire({
              type: 'deepLink',
              payload: { url: 'tel:40021552' },
            })}
          />
        </Box>

        <SeparatorHorizontal mv="xs" />

        <Text type="subtitleXXL" mb="nano">Error Cases</Text>
        <Box mb="xs" style={{ gap: 8 }}>
          <Button
            text="Navigate without screen (error)"
            variant="secondary"
            onPress={() => fire({
              type: 'navigate',
              payload: {},
            })}
          />
          <Button
            text="Deep Link without url (error)"
            variant="secondary"
            onPress={() => fire({
              type: 'deepLink',
              payload: {},
            })}
          />
        </Box>

        <SeparatorHorizontal mv="xs" />

        <Text type="subtitleXXL" mb="nano">
          Action Log ({log.length})
        </Text>
        {log.length === 0 && (
          <Text type="bodySM" color="INTENSE_COLOR_03">
            Press a button above to see results here.
          </Text>
        )}
        {log.map(entry => (
          <View
            key={entry.id}
            style={{
              backgroundColor: entry.result.success ? '#E8F5E9' : '#FFEBEE',
              borderRadius: 8,
              padding: 10,
              marginBottom: 6,
            }}
          >
            <Text type="bodySM">
              [{entry.timestamp}] {entry.type} → {entry.result.success ? 'SUCCESS' : 'FAILED'}
            </Text>
            {entry.payload && (
              <Text type="bodySM" color="INTENSE_COLOR_03">
                {JSON.stringify(entry.payload)}
              </Text>
            )}
            {entry.result.error && (
              <Text type="bodySM" color="DEEP_COLOR_SEMANTICS_02">
                {entry.result.error}
              </Text>
            )}
          </View>
        ))}
      </Box>
    </ScrollView>
  );
}

