        <Box mb="xs">
          <Button
            text="Replace → SuccessScreen"
            onPress={() => fire({
              type: 'replace',
              payload: { screen: 'SuccessScreen', params: { orderId: 'ORD-001' } },
            })}
          />
        </Box>

        <Text type="subtitleXXL" mb="nano">deepLink</Text>
        <Box mb="xs" style={{ gap: 8 }}>
          <Button
            text="Deep Link → app://rewards/voucher/123"
            onPress={() => fire({
              type: 'deepLink',
              payload: { url: 'app://rewards/voucher/123' },
            })}
          />
          <Button
            text="Deep Link → tel:40021552"
            onPress={() => fire({
