    expect(result.success).toBe(false);
    expect(result.error).toContain('requires a "screen"');
  });
});

describe('deepLinkHandler', () => {
  it('calls linking.openURL with the url', () => {
    const deps = createNavDeps();
    const result = deepLinkHandler(
      { url: 'app://rewards/voucher/123' },
      mockActionContext,
      deps,
    );

    expect(result.success).toBe(true);
    expect(deps.linking!.openURL).toHaveBeenCalledWith('app://rewards/voucher/123');
  });

