    expect(result.success).toBe(false);
    expect(result.error).toContain('requires a "url"');
  });

  it('fails when payload is undefined', () => {
    const deps = createNavDeps();
    const result = deepLinkHandler(undefined, mockActionContext, deps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('requires a "url"');
  });
});

describe('integration with ActionRegistry', () => {
  it('handlers work with executeAction via registry', async () => {
    const { createActionRegistry, executeAction } = require('./registry');
    const deps = createNavDeps();

    let registry = createActionRegistry();
    registry = { ...registry, navigate: navigateHandler, goBack: goBackHandler };

    const navResult = await executeAction(
      registry,
      { type: 'navigate', payload: { screen: 'Detail', params: { id: '1' } } },
      mockActionContext,
      deps,
    );
    expect(navResult.success).toBe(true);
    expect(deps.navigation!.navigate).toHaveBeenCalledWith('Detail', { id: '1' });

    const backResult = await executeAction(
      registry,
      { type: 'goBack' },
      mockActionContext,
      deps,
    );
    expect(backResult.success).toBe(true);
    expect(deps.navigation!.goBack).toHaveBeenCalled();
  });
});

